import React, { useState, useEffect } from "react";
import api from "../../api/axios";
import toast from "react-hot-toast";
import "./Admin.css";

const IELTS_PARTS = ["Writing Task 1", "Writing Task 2", "Speaking Part 1", "Speaking Part 2", "Speaking Part 3"];
const TOEIC_PARTS = ["Speaking", "Writing"];

const INIT = { lessonId: "", title: "", description: "", type: "writing", examType: "IELTS", examPart: "", maxScore: 100, deadline: "" };

export default function AdminAssignments() {
  const [assignments, setAssignments] = useState([]);
  const [lessons, setLessons] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(false);
  const [form, setForm] = useState(INIT);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [aRes, lRes] = await Promise.all([
        api.get("/assignments").catch(() => ({ data: { data: [] } })),
        api.get("/lessons").catch(() => ({ data: { data: [] } }))
      ]);
      setAssignments(aRes.data.data || []);
      setLessons(lRes.data.data || []);
    } catch { toast.error("Không thể tải dữ liệu"); }
    finally { setLoading(false); }
  };

  useEffect(() => { fetchData(); }, []);

  const getAvailableParts = () => form.examType === "IELTS" ? IELTS_PARTS : TOEIC_PARTS;

  const handleSave = async () => {
    if (!form.title) { toast.error("Nhập tiêu đề"); return; }
    try {
      await api.post("/assignments", { ...form, lessonId: form.lessonId ? Number(form.lessonId) : null, maxScore: Number(form.maxScore) });
      toast.success("Tạo bài tập thành công"); setModal(false); fetchData();
    } catch (e) { toast.error(e.response?.data?.message || "Thất bại"); }
  };

  return (
    <div className="admin-page fade-in">
      <div className="page-header">
        <h1>Quản lý bài tập</h1>
        <p>Tạo bài tập Writing và Speaking theo chuẩn IELTS/TOEIC</p>
      </div>
      <div className="toolbar">
        <div className="toolbar-left" />
        <button className="btn btn-primary" onClick={() => { setForm(INIT); setModal(true); }}>+ Tạo bài tập</button>
      </div>

      <div className="table-wrapper">
        {loading ? <div className="page-loading"><div className="spinner" /></div> : (
          <table className="data-table">
            <thead><tr><th>Tiêu đề</th><th>Loại</th><th>Phần</th><th>Điểm tối đa</th><th>Hạn nộp</th><th>Trạng thái</th></tr></thead>
            <tbody>
              {assignments.length === 0
                ? <tr><td colSpan={6} className="empty-state"><p>Chưa có bài tập nào</p></td></tr>
                : assignments.map(a => (
                  <tr key={a.id}>
                    <td style={{ fontWeight: 500 }}>{a.title}</td>
                    <td><span className={`badge ${a.examType === "IELTS" ? "badge-blue" : "badge-green"}`}>{a.examType}</span></td>
                    <td>{a.examPart || "—"}</td>
                    <td>{a.maxScore}</td>
                    <td style={{ fontSize: "0.82rem" }}>{a.deadline ? new Date(a.deadline).toLocaleDateString("vi-VN") : "—"}</td>
                    <td><span className={`badge ${a.status === "active" ? "badge-green" : a.status === "closed" ? "badge-gray" : "badge-red"}`}>{a.status}</span></td>
                  </tr>
                ))
              }
            </tbody>
          </table>
        )}
      </div>

      {modal && (
        <div className="modal-overlay" onClick={() => setModal(false)}>
          <div className="modal" style={{ maxWidth: 580 }} onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>Tạo bài tập mới</h3>
              <button className="modal-close" onClick={() => setModal(false)}>✕</button>
            </div>
            <div className="modal-body">
              <div className="form-row">
                <div className="form-group"><label>Loại chứng chỉ</label>
                  <select value={form.examType} onChange={e => setForm({ ...form, examType: e.target.value, examPart: "" })}>
                    <option value="IELTS">IELTS</option>
                    <option value="TOEIC">TOEIC</option>
                    <option value="OTHER">Khác</option>
                  </select>
                </div>
                <div className="form-group"><label>Dạng bài tập</label>
                  <select value={form.type} onChange={e => setForm({ ...form, type: e.target.value })}>
                    <option value="writing">Writing ✍️</option>
                    <option value="speaking">Speaking 🎤</option>
                  </select>
                </div>
              </div>

              <div className="form-group"><label>Phần thi cụ thể</label>
                <select value={form.examPart} onChange={e => setForm({ ...form, examPart: e.target.value })}>
                  <option value="">— Chọn phần —</option>
                  {getAvailableParts().map(p => <option key={p} value={p}>{p}</option>)}
                </select>
              </div>

              <div className="form-group"><label>Tiêu đề bài tập *</label>
                <input value={form.title} onChange={e => setForm({ ...form, title: e.target.value })}
                  placeholder={`VD: ${form.examType} ${form.examPart || "Writing"} Practice`} />
              </div>

              <div className="form-group"><label>Đề bài / Mô tả</label>
                <textarea rows={5} value={form.description} onChange={e => setForm({ ...form, description: e.target.value })}
                  placeholder={
                    form.examPart === "Writing Task 1"
                      ? "VD: The chart below shows... Summarise the information by selecting and reporting the main features..."
                      : form.examPart === "Writing Task 2"
                      ? "VD: Some people believe that... To what extent do you agree or disagree?"
                      : "Nhập đề bài hoặc hướng dẫn làm bài..."
                  } />
              </div>

              <div className="form-row">
                <div className="form-group"><label>Điểm tối đa</label>
                  <input type="number" value={form.maxScore} onChange={e => setForm({ ...form, maxScore: e.target.value })} min={0} max={100} />
                </div>
                <div className="form-group"><label>Hạn nộp bài</label>
                  <input type="datetime-local" value={form.deadline} onChange={e => setForm({ ...form, deadline: e.target.value })} />
                </div>
              </div>

              <div className="form-group"><label>Liên kết bài học</label>
                <select value={form.lessonId} onChange={e => setForm({ ...form, lessonId: e.target.value })}>
                  <option value="">Không liên kết</option>
                  {lessons.map(l => <option key={l.id} value={l.id}>{l.title}</option>)}
                </select>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-ghost" onClick={() => setModal(false)}>Hủy</button>
              <button className="btn btn-primary" onClick={handleSave}>Tạo bài tập</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
